        None
    }
}

/// Extract the extension(s) from a filename (e.g., "nii.gz", "json")
fn extract_extension(filename: &str) -> Option<String> {
    if let Some(dot_pos) = filename.find('.') {
        Some(filename[dot_pos + 1..].to_string())
    } else {
        None
    }
}

/// Template layout containing all files for available templates
#[derive(Debug, Default, Serialize, Deserialize)]
pub struct TemplateLayout {
    /// Map from template name to list of files
    pub templates: HashMap<String, Vec<TemplateFile>>,
}

impl TemplateLayout {
    /// Create a new empty layout
    pub fn new() -> Self {
        Self::default()
    }

    /// Add a file to the layout
    pub fn add_file(&mut self, file: TemplateFile) {
        self.templates
            .entry(file.template.clone())
            .or_insert_with(Vec::new)
            .push(file);
    }

    /// Get all templates
    pub fn get_templates(&self) -> Vec<&str> {
        self.templates.keys().map(|s| s.as_str()).collect()
    }

    /// Get files for a specific template
    pub fn get_template_files(&self, template: &str) -> Option<&[TemplateFile]> {
        self.templates.get(template).map(|v| v.as_slice())
    }

    /// Query files across all templates
    pub fn query(&self, query: &HashMap<String, String>) -> Vec<&TemplateFile> {
        let mut results = Vec::new();

        // If template is specified in query, only search that template
        if let Some(template) = query.get("tpl") {
            if let Some(files) = self.templates.get(template) {
                for file in files {
                    if file.matches(query) {
                        results.push(file);
                    }
                }
            }
        } else {
            // Search all templates
            for files in self.templates.values() {
                for file in files {
                    if file.matches(query) {
                        results.push(file);
                    }
                }
            }
        }

        results
    }
}

/// Parse the templateflow skeleton from a zip file
pub fn parse_skeleton<R: std::io::Read + std::io::Seek>(reader: R) -> Result<TemplateLayout> {
    use zip::ZipArchive;

    let mut archive = ZipArchive::new(reader)
        .map_err(|e| TemplateFlowError::IoError(e.into()))?;

    let mut layout = TemplateLayout::new();

    for i in 0..archive.len() {
        let file = archive.by_index(i)
            .map_err(|e| TemplateFlowError::IoError(e.into()))?;

        let path = PathBuf::from(file.name());

        // Skip directories and non-template files
        if file.is_dir() || !path.starts_with("tpl-") {
            continue;
        }

        // Skip files without proper parent directory
        if path.parent().is_none() {
            continue;
        }

        // Try to parse as a template file
        match TemplateFile::from_path(&path) {
            Ok(template_file) => {
                layout.add_file(template_file);
            }
            Err(_) => {
                // Skip files that don't parse as valid BIDS files
                continue;
            }
        }
    }

    Ok(layout)
}

/// Load the skeleton from a file path
pub fn load_skeleton_from_file(path: &Path) -> Result<TemplateLayout> {
    use std::fs::File;

    let file = File::open(path)?;
    parse_skeleton(file)
}

/// Load the skeleton from bytes
pub fn load_skeleton_from_bytes(bytes: &[u8]) -> Result<TemplateLayout> {
    use std::io::Cursor;

    let cursor = Cursor::new(bytes);
    parse_skeleton(cursor)
}

