    let mut archive = ZipArchive::new(reader)
        .map_err(|e| TemplateFlowError::IoError(e.into()))?;

    let mut layout = TemplateLayout::new();
    let mut metadata_files = HashMap::new();

    // First pass: collect all files and metadata
    for i in 0..archive.len() {
        let mut file = archive.by_index(i)
            .map_err(|e| TemplateFlowError::IoError(e.into()))?;

        let path = PathBuf::from(file.name());

        // Skip directories and non-template files
        if file.is_dir() || !path.starts_with("tpl-") {
            continue;
        }

        // Skip files without proper parent directory
        if path.parent().is_none() {
            continue;
        }

        // Check if this is a template_description.json file
        if path.file_name() == Some(std::ffi::OsStr::new("template_description.json")) {
            // Extract template name from parent directory
            if let Some(parent) = path.parent() {
                if let Some(parent_name) = parent.file_name() {
                    if let Some(template_name) = parent_name.to_str() {
                        if template_name.starts_with("tpl-") {
                            let template = template_name.strip_prefix("tpl-").unwrap();
                            let mut content = String::new();
                            file.read_to_string(&mut content)
                                .map_err(|e| TemplateFlowError::IoError(e))?;
                            metadata_files.insert(template.to_string(), content);
                        }
                    }
                }
            }
        } else {
            // Try to parse as a template file
            match TemplateFile::from_path(&path) {
                Ok(template_file) => {
                    layout.add_file(template_file);
                }
                Err(_) => {
                    // Skip files that don't parse as valid BIDS files
                    continue;
                }
            }
        }
    }

    // Second pass: parse metadata files
    for (template, json_content) in metadata_files {
        match TemplateMetadata::from_json(&json_content) {
            Ok(metadata) => {
                layout.add_metadata(&template, metadata);
            }
            Err(e) => {
                // Log error but don't fail the entire parsing
                eprintln!("Failed to parse metadata for template {}: {}", template, e);
            }
        }
    }

    Ok(layout)
}

